void TransitionMatrix::preprocess(const RawMatrix& raw)
{
    processed_states.resize(raw.size());

    for (size_t si = 0; si < raw.size(); ++si) {

        State& state = processed_states[si];
        for (const auto& [key, next] : raw[si]) {

            state.matches[key[0]] = next;

            // Wildcard 
            if (key == "{*}") {
                state.wildcard = next;
                continue;
            }
        }
    }
}

TransitionMatrix::TransitionMatrix()
{
    preprocess(k_raw_matrix);
}


int TransitionMatrix::lookup(int state_index, char c) const
{
    if (state_index < 0 || static_cast<size_t>(state_index) >= processed_states.size())
        return -1;

    const State& state = processed_states[state_index];

    // Exact match — O(1)
    auto it = state.matches.find(c);
    if (it != state.matches.end())
        return it->second;

    // Wildcard — O(1)
    return state.wildcard;
}